"""
MKT Christ Commentary — Isaiah chapter 66
Run: python3 scripts/zc-christ-isaiah-66.py

Isaiah 66 is the eschatological finale of the entire book:
1. vv.1-4: Temple critique + the contrite receiver of the word
2. vv.5-6: Vindication of the ostracized believers; divine recompense
3. vv.7-13: Zion's miraculous birth, nursing metaphors, maternal comfort
4. vv.14-17: Divine warrior in fire; universal judgment
5. vv.18-21: Universal gathering of nations; Gentile priests
6. vv.22-24: New creation permanence; universal Sabbath worship;
   undying worm and unquenched fire (most-cited OT text in Jesus's Gehenna teaching)

Key Christological texts:
- 66:1-2: "Heaven is my throne" → Acts 7:48-50 (Stephen's citation);
  Matt 12:6; John 4:21-23
- 66:2: "contrite and lowly in spirit" → Matt 5:3; Luke 18:13-14
- 66:5: cast out for his name → John 9:22,34; John 16:2
- 66:13: "as a mother comforts" → John 14:16-18 (the Paraclete/Comforter)
- 66:22: new heavens and new earth → Rev 21:1; 2 Pet 3:13
- 66:24: undying worm, unquenched fire → Mark 9:44,46,48 (Jesus quotes three times)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "66": {
    "1": '<p>"Thus says YHWH: \'Heaven is my throne and the earth is my footstool; what is the house that you would build for me, and what is the place of my rest?\'" Acts 7:48-50: Stephen quotes these two verses verbatim in his speech before the Sanhedrin — the longest direct OT citation in Acts, immediately before his martyrdom. Stephen uses it to argue that "the Most High does not dwell in houses made by hands." John 4:21-23: Jesus tells the Samaritan woman "the hour is coming when neither on this mountain nor in Jerusalem will you worship the Father... the hour is coming, and is now here, when the true worshipers will worship the Father in spirit and truth." Matt 12:6: "I tell you, something greater than the temple is here." The incarnate Christ is the true temple (John 2:19-21: "he was speaking about the temple of his body") — the one the heavens cannot contain dwelling in human flesh.</p>',
    "2": '<p>"All these things my hand has made, and so all these things came to be, declares YHWH. But this is the one to whom I will look: he who is humble and contrite in spirit and trembles at my word." The divine preference — the cosmic Creator who fills all space chooses to look at the one who is humble. Matt 5:3: "Blessed are the poor in spirit, for theirs is the kingdom of heaven." Luke 18:13-14: the tax collector who "would not even lift up his eyes to heaven, but beat his breast, saying, \'God, be merciful to me, a sinner!\' — this man went down to his house justified, rather than the other." Jas 4:6: "God opposes the proud but gives grace to the humble." Heb 5:7: Christ in Gethsemane offered "prayers and supplications, with loud cries and tears, to him who was able to save him" — the Son who "trembles at my word" is the perfect embodiment of the contrite spirit of Isaiah 66:2, the one on whom the Father\'s eyes permanently rest.</p>',
    "3": '<p>"He who slaughters an ox is like one who kills a man; he who sacrifices a lamb, like one who breaks a dog\'s neck; he who presents a grain offering, like one who offers pig\'s blood; he who makes a memorial offering of frankincense, like one who blesses an idol." The radical critique of heartless sacrifice — when the worshipper chooses his own ways (v.3b), every correct ritual act becomes its opposite. Matt 5:23-24: "if you are offering your gift at the altar and there remember that your brother has something against you, leave your gift there before the altar and go. First be reconciled to your brother." Mark 7:6-8: Jesus cites Isa 29:13 on worship that is lips without heart. Heb 10:5-7: Christ enters saying "Sacrifices and offerings you have not desired, but a body you have prepared for me... I have come to do your will, O God" — the sacrifice that is NOT like the empty ritual of 66:3 but the genuine self-offering that fulfills all that the sacrifices pointed toward.</p>',
    "4": '<p>"I also will choose harsh treatment for them and bring their fears upon them, because when I called, no one answered, when I spoke, they did not listen; but they did evil in my sight and chose that in which I did not delight." The divine response to unrequited calling. Matt 22:3: "he sent his servants to call those who were invited to the wedding feast, but they would not come." Luke 13:34: "how often would I have gathered your children together as a hen gathers her brood under her wings, and you were not willing!" John 5:25: "an hour is coming, and is now here, when the dead will hear the voice of the Son of God, and those who hear will live" — the voice that meets no answer from the living finds answer from the dead. The "calling with no answer" of Isaiah 66:4 is what Christ laments over Jerusalem (Matt 23:37-38: "your house is left to you desolate") and what John diagnoses as the rejection of the incarnate Word (John 1:11: "he came to his own, and his own people did not receive him").</p>',
    "5": '<p>"Hear the word of YHWH, you who tremble at his word: \'Your brothers who hate you and cast you out for my name\'s sake have said, "Let YHWH be glorified, that we may see your joy"; but it is they who shall be put to shame.\'" The ostracized believers — cast out by religious community "for my name\'s sake" — who will be vindicated. John 9:22,34: the healed blind man "was cast out" of the synagogue for confessing Christ. John 16:2: "they will put you out of the synagogues. Indeed, the hour is coming when whoever kills you will think he is offering service to God." Rev 3:9: the letter to Philadelphia — "I will make those of the synagogue of Satan... come and bow down before your feet, and they will learn that I have loved you." The casting-out for YHWH\'s name is the discipleship cost that Christ predicted (Luke 6:22: "Blessed are you when people hate you and when they exclude you and revile you and spurn your name as evil, on account of the Son of Man").</p>',
    "6": '<p>"The sound of an uproar from the city! A sound from the temple! The sound of YHWH, rendering recompense to his enemies!" The divine recompense from the city and temple. Matt 24:2: "you see all these things? Truly, I say to you, there will not be left here one stone upon another that will not be thrown down." Luke 19:43-44: "the days will come upon you, when your enemies will set up a barricade around you... and tear you down to the ground." Rev 18:10: "Alas, alas, for the great city... for in a single hour your judgment has come!" Heb 12:26: "his voice then shook the earth, but now he has promised, \'Yet once more I will shake not only the earth but also the heavens.\'" The sound from the temple is both the AD 70 judgment Jesus predicted and the eschatological shaking at the parousia.</p>',
    "7": '<p>"Before she was in labor she gave birth; before her pain came upon her she delivered a son." The miraculous community-birth before the expected labor pains. John 3:5-8: "unless one is born of water and the Spirit, he cannot enter the kingdom of God... the wind blows where it wishes." Rev 12:2,5: the heavenly woman "was pregnant and was crying out in birth pains," giving birth to "a male child who is to rule all the nations with a rod of iron" — Christ himself, and then the messianic community. The birth before labor is the new creation\'s reversal of the curse (Gen 3:16: "in pain you shall bring forth children") — the Spirit\'s birth of the church is painless on the part of the receiver precisely because the labor-pain was borne by the Son on the cross. John 16:21: "a woman giving birth has sorrow... but when she has delivered the baby, she no longer remembers the anguish for joy that a human being has been born into the world" — the very metaphor Jesus uses for his death-and-resurrection.</p>',
    "8": '<p>"Who has heard such a thing? Who has seen such things? Shall a land be born in one day? Shall a nation be brought forth in one moment? For as soon as Zion was in labor she brought forth her children." Acts 2:41: "those who received his word were baptized, and there were added that day about three thousand souls" — a nation born in one day at Pentecost. Acts 2:1: "when the day of Pentecost arrived, they were all together in one place." The one-day nation-birth of Isaiah 66:8 is the church at Pentecost — the community brought forth in a moment when the Spirit was poured out. The rhetorical questions ("who has heard such a thing?") are answered by the Pentecost narrative: the astonished crowd in Acts 2:7-12 ("are not all these who are speaking Galileans?") witnesses the unprecedented birth of the new community from every language under heaven.</p>',
    "9": '<p>"\'Shall I bring to the point of birth and not cause to bring forth?\' says YHWH; \'shall I, who cause to bring forth, shut the womb?\' says your God." The divine commitment to complete what he began. Phil 1:6: "I am sure of this, that he who began a good work in you will bring it to completion at the day of Jesus Christ." 1 Thess 5:24: "he who calls you is faithful; he will surely do it." John 6:37-39: "all that the Father gives me will come to me, and whoever comes to me I will never cast out... and this is the will of him who sent me, that I should lose nothing of all that he has given me." The divine midwifery that will not abandon the labor is the perseverance of Christ in intercession: Heb 7:25: "he always lives to make intercession" for those who draw near to God through him — the Father will not shut the womb of the new creation.</p>',
    "10": '<p>"Rejoice with Jerusalem, and be glad for her, all you who love her; rejoice with her in joy, all you who mourn over her." The call to communal celebration with the redeemed city. Rev 19:7: "Let us rejoice and exult and give him the glory, for the marriage of the Lamb has come, and his Bride has made herself ready." Rev 18:20: "Rejoice over her, O heaven, and you saints and apostles and prophets, for God has given judgment for you against her!" Matt 5:4: "Blessed are those who mourn, for they shall be comforted" — the mourners over Jerusalem in Isaiah 66:10 are the beatitude-mourners who will be comforted. Luke 19:41: "when he drew near and saw the city, he wept over it" — Christ himself mourns for Jerusalem before its judgment. His mourning is the deeper form of the love that Isaiah 66:10 calls for.</p>',
    "11": '<p>"That you may nurse and be satisfied from her consoling breast; that you may drink deeply with delight from her glorious abundance." The nursing-satisfaction from the abundant city. 1 Pet 2:2: "like newborn infants, long for the pure spiritual milk, that by it you may grow up into salvation — if indeed you have tasted that the Lord is good." John 6:35: "I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst." Heb 5:12-14: the contrast between milk (for infants) and solid food (for the mature) — the nursing of Isaiah 66:11 is the beginning of the spiritual nourishment that Christ provides and that grows toward maturity. Rev 22:17: "let the one who is thirsty come; let the one who desires take the water of life without price."</p>',
    "12": '<p>"For thus says YHWH: \'Behold, I will extend peace to her like a river, and the glory of the nations like an overflowing stream.\'" Peace like a river. John 7:38-39: "Whoever believes in me, as the Scripture has said, \'Out of his heart will flow rivers of living water.\' Now this he said about the Spirit." Rev 22:1: "the river of the water of life, bright as crystal, flowing from the throne of God and of the Lamb." Isa 57:19: "Peace, peace, to the far and to the near." Phil 4:7: "the peace of God, which surpasses all understanding, will guard your hearts and your minds in Christ Jesus." The overflowing-stream glory of the nations is the Gentile wealth flowing into the city of Isaiah 60:11 — what began with the Magi\'s gold and frankincense (60:6) reaches its consummation in the river of life from the Lamb\'s throne.</p>',
    "13": '<p>"\'As one whom his mother comforts, so I will comfort you; you shall be comforted in Jerusalem.\'" The maternal comfort of God. 2 Cor 1:3-4: "the God of all comfort, who comforts us in all our affliction." Matt 5:4: "Blessed are those who mourn, for they shall be comforted." John 14:16-18: "I will ask the Father, and he will give you another Helper [<em>Paráklēton</em> — Comforter]... I will not leave you as orphans; I will come to you." The Holy Spirit is named Paraclete (Comforter, Helper) — the fulfillment of the maternal comfort promised in Isaiah 66:13. The Greek <em>paraklētos</em> can mean advocate, helper, or comforter — all three senses apply to the Spirit\'s ministry to the church that mourns and awaits full comfort. The divine comfort that surpasses all understanding (Phil 4:7) is the Spirit\'s application of what Christ accomplished.</p>',
    "14": '<p>"You shall see, and your heart shall rejoice; your bones shall flourish like the grass; and the hand of YHWH shall be known to his servants, and he shall show his indignation against his enemies." The rejoicing with flourishing bones. Ezek 37:1-14: the valley of dry bones that come to life — the resurrection of the whole people. John 20:20: "when he had said this, he showed them his hands and his side. Then the disciples were glad when they saw the Lord." The seeing-and-rejoicing is the post-resurrection encounter: John 16:22: "you have sorrow now, but I will see you again, and your hearts will rejoice, and no one will take your joy from you." The "bones flourishing like the grass" is the new creation\'s resurrection vitality — the spring after the winter of judgment (66:15-17). 1 Cor 15:42-44: "the dead is raised imperishable... it is sown in weakness; it is raised in power."</p>',
    "15": '<p>"For behold, YHWH will come in fire, and his chariots like the whirlwind, to render his anger in fury, and his rebuke with flames of fire." The divine warrior\'s eschatological coming. 2 Thess 1:7-8: "when the Lord Jesus is revealed from heaven with his mighty angels in flaming fire, inflicting vengeance on those who do not know God and on those who do not obey the gospel of our Lord Jesus." Rev 19:11-14: "heaven opened, and behold, a white horse! The one sitting on it is called Faithful and True... his eyes are like a flame of fire... he is clothed in a robe dipped in blood." Heb 12:29: "our God is a consuming fire." The fiery coming of YHWH in the chariots of heaven (cf. 2 Kings 2:11; 6:17 — the chariots of fire that Elisha saw) is the return of Christ at the parousia.</p>',
    "16": '<p>"For by fire will YHWH enter into judgment, and by his sword, with all flesh; and those slain by YHWH shall be many." The universal scope of eschatological judgment. Rev 19:15: "from his mouth comes a sharp sword with which to strike down the nations, and he will rule them with a rod of iron." Matt 25:41: "depart from me, you cursed, into the eternal fire prepared for the devil and his angels." Rev 20:12-15: the great white throne judgment — "the dead were judged by what was written in the books, according to what they had done." The "many slain" is the dark counterpart to the many who will be made righteous through the one Man\'s obedience (Rom 5:19) — there is a multitude for judgment as surely as a multitude for salvation (Rev 7:9).</p>',
    "17": '<p>"Those who sanctify and purify themselves to go into the gardens, following one in the midst, eating pig\'s flesh and the abomination and mice, shall come to an end together, declares YHWH." The final judgment on false purification rituals — people who perform cleansing rites while eating the forbidden. Acts 10:15: Peter\'s vision: "What God has made clean, do not call common" — the food laws in question are now reframed in Christ. Mark 7:18-20: Jesus declares "there is nothing outside a person that by going into him can defile him... what comes out of a person is what defiles him." The irony of Isaiah 66:17: those who elaborate their purification rituals are consuming precisely what defiles them. Heb 9:14: "how much more will the blood of Christ, who through the eternal Spirit offered himself without blemish to God, purify our conscience from dead works to serve the living God."</p>',
    "18": '<p>"For I know their works and their thoughts, and the time is coming to gather all nations and tongues. And they shall come and shall see my glory." The universal assembly before the divine glory. John 17:24: "Father, I desire that they also, whom you have given me, may be with me where I am, to see my glory that you have given me before the foundation of the world." Acts 2:5-11: "devout men from every nation under heaven" at Pentecost — the first gathering of all tongues for the divine revelation. Rev 7:9: "a great multitude that no one could number, from every nation, from all tribes and peoples and languages, standing before the throne and before the Lamb." The gathering to see YHWH\'s glory in Isaiah 66:18 is the gathering to see the Lamb\'s glory in Revelation — for John 12:41 has already identified the Isaiah-glory as Christ\'s glory.</p>',
    "19": '<p>"And I will set a sign among them. And from them I will send survivors to the nations, to Tarshish, Pul, and Lud, who draw the bow, to Tubal and Javan, to the coastlands far away, that have not heard my fame or seen my glory. And they shall declare my glory among the nations." The missionary sending. Matt 28:19-20: "Go therefore and make disciples of all nations." Acts 1:8: "you will be my witnesses in Jerusalem and in all Judea and Samaria, and to the end of the earth." The geographic expansion of Isaiah 66:19 (Tarshish = Spain; Javan = Greece) is the same expansion of Acts and Paul\'s mission: Rom 15:20 (Paul\'s ambition to preach where Christ has not been named); Rom 15:24 (Spain as the ultimate western frontier). The "survivors sent" are the apostles and missionaries sent out after the Pentecost gathering — the ones who have seen the glory (66:18) and now carry it to where no one has heard.</p>',
    "20": '<p>"And they shall bring all your brothers from all the nations as an offering to YHWH, on horses and in chariots and in litters and on mules and on dromedaries, to my holy mountain Jerusalem, says YHWH, just as the Israelites bring their grain offering in a clean vessel to the house of YHWH." The nations bringing Israel\'s scattered brothers as a holy offering to YHWH. Rom 15:16: Paul describes his apostolic work as "the priestly service of the gospel of God, so that the offering of the Gentiles may be acceptable, sanctified by the Holy Spirit" — Paul explicitly uses the sacrifice-offering metaphor for his missionary work, applying the Isaiah 66:20 logic to his Gentile congregations. The universal transport vehicles (horses, chariots, litters, camels) are the entire transportation capacity of the ancient world pressed into service for the ingathering — all human movement reoriented toward the holy mountain.</p>',
    "21": '<p>"And some of them also I will take for priests and for Levites, says YHWH." The shocking promise: some from the Gentile nations will become priests and Levites. 1 Pet 2:9: "you are a chosen race, a royal priesthood, a holy nation, a people for his own possession, that you may proclaim the excellencies of him who called you out of darkness into his marvelous light." Rev 5:10: the four living creatures and twenty-four elders sing of the Lamb: "you have made them a kingdom and priests to our God, and they shall reign on the earth." Rev 20:6: "Blessed and holy is the one who shares in the first resurrection! Over such the second death has no power, but they will be priests of God and of Christ." The Levitical exclusivity — the closed priestly lineage — is abolished through Christ who is both the ultimate Priest (Heb 4:14) and the one who makes his people priests (Rev 1:6).</p>',
    "22": '<p>"\'For as the new heavens and the new earth that I make shall remain before me,\' says YHWH, \'so shall your offspring and your name remain.\'" The new creation as permanent reality. Rev 21:1: "I saw a new heaven and a new earth, for the first heaven and the first earth had passed away." 2 Pet 3:13: "we are waiting for new heavens and a new earth in which righteousness dwells." The permanence of the offspring and name is the permanence of the church in Christ: Matt 16:18: "the gates of hell shall not prevail against it." Heb 12:28: "we are receiving a kingdom that cannot be shaken." The "offspring" (<em>zarʿakem</em>) that remains is the Abrahamic seed fulfilled in Christ and the church — Gal 3:29: "if you are Christ\'s, then you are Abraham\'s offspring, heirs according to promise."</p>',
    "23": '<p>"\'From new moon to new moon, and from Sabbath to Sabbath, all flesh shall come to worship before me,\' says YHWH." The universal perpetual worship — the entire human calendar reoriented toward YHWH. John 4:23-24: "the true worshipers will worship the Father in spirit and truth, for the Father is seeking such people to worship him." Rev 15:4: "Who will not fear, O Lord, and glorify your name? For you alone are holy. All nations will come and worship you, for your righteous acts have been revealed." Heb 4:9-10: "there remains a Sabbath rest for the people of God, for whoever has entered God\'s rest has also rested from his works as God did from his." The continuous Sabbath worship of Isaiah 66:23 is the eternal rest-in-worship that Hebrews says awaits the people of God — entered now through faith in Christ, consummated at the resurrection.</p>',
    "24": '<p>"\'And they shall go out and look on the dead bodies of the men who have rebelled against me. For their worm shall not die, their fire shall not be quenched, and they shall be an abhorrence to all flesh.\'" The disturbing final verse — the undying worm and unquenched fire. Jesus quotes this verse three times in Mark 9: vv.44,46,48 — "where their worm does not die and the fire is not quenched" — applied to Gehenna (the valley of Hinnom, Jerusalem\'s burning refuse site used as a symbol of ultimate judgment). It is one of the most-cited OT texts in Jesus\'s teaching. Matt 25:46: "these will go away into eternal punishment." Rev 14:11: "the smoke of their torment goes up forever and ever, and they have no rest, day or night." Isaiah closes not with the beatific vision but with the warning that makes the beatific vision so urgent. The whole of Isaiah\'s Christology — the Servant who bore the worm and the fire (53:10: "it was the will of YHWH to crush him") — was to rescue those who by grace tremble at his word (66:2) from the fate of those who refuse the Redeemer (47:4) and remain under the worm and the fire.</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    # INTENT: Verify all 24 Isaiah 66 mkt-christ verses present against interlinear
    # CHANGE? If interlinear/isaiah.json ch 66 verse count changes, update expected total
    # VERIFY: Console shows OK with 24 verses; no MISSING output
    il = json.loads((ROOT / 'data' / 'interlinear' / 'isaiah.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-christ' / 'isaiah.json').read_text())
    missing = [v for v in il.get('66', {}) if v not in out.get('66', {})]
    if missing:
        print(f'  MISSING ch 66: {missing}')
    else:
        print(f'  OK: all Isaiah 66 mkt-christ verses present ({len(il.get("66", {}))} verses)')

if __name__ == '__main__':
    main()
